#include <stdio.h>
#include <string.h>

int longestCommonSubstr(char *str1, char *str2) {
    int n = strlen(str1);
    int m = strlen(str2);
    int dp[n + 1][m + 1];
    int ans = 0;
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (str1[i - 1] == str2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
                ans = (ans > dp[i][j]) ? ans : dp[i][j];
            } else {
                dp[i][j] = 0;
            }
        }
    }
    return ans;
}

int main() {
    char str1[100], str2[100];
    scanf("%s %s", str1, str2);
    printf("%d\n", longestCommonSubstr(str1, str2));
    return 0;
}

